	// 
	// am_plane_takedown.c 
	// network_explode_vehicle(net_to_veh(Local_40.imm_2), 1, 1, 0);
	// 
	// armenian2.c 
	// network_explode_vehicle(Local_80[6 <2>], 1, 0, 0);
