	// Dim ped_handle As Integer
	//                     With Game.Player.Character
	//                         Dim pos As Vector3 = .Position + .ForwardVector * 3
	//                         ped_handle = Native.Function.Call(Of Integer)(Hash.CREATE_RANDOM_PED, pos.X, pos.Y, pos.Z)
